/**
 * Unit tests for task-agent-advisor PreToolUse[Task] hook
 *
 * Covers the generic→specialist prompt-shape nudge (general-purpose tasks
 * with a clear domain get a "consider ork:X" context line) plus the
 * pre-existing synonym and casing suggestions.
 */

import { existsSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';
import { describe, test, expect } from 'vitest';
import type { HookInput } from '../../types.js';
import {
  taskAgentAdvisor,
  matchSpecialistDomain,
  isDeterministicRunTask,
  ORK_AGENT_SYNONYMS,
  SPECIALIST_DOMAINS,
} from '../../pretool/task/task-agent-advisor.js';

// Repo-root src/agents/, resolved from this test file's location
// (vitest runs with cwd=src/hooks, so cwd-relative paths would be wrong).
const AGENTS_DIR = join(dirname(fileURLToPath(import.meta.url)), '../../../../../src/agents');

function makeInput(toolInput: Record<string, unknown>): HookInput {
  return {
    tool_name: 'Task',
    session_id: 'session-advisor',
    tool_input: toolInput,
  };
}

function contextOf(result: ReturnType<typeof taskAgentAdvisor>): string {
  return (result.hookSpecificOutput?.additionalContext as string) || '';
}

function reasonOf(result: ReturnType<typeof taskAgentAdvisor>): string {
  return (result.hookSpecificOutput?.permissionDecisionReason as string) || '';
}
function decisionOf(result: ReturnType<typeof taskAgentAdvisor>): string {
  return (result.hookSpecificOutput?.permissionDecision as string) || '';
}

describe('matchSpecialistDomain', () => {
  test.each([
    ['investigate the failure in the deploy job and find the root cause', 'ork:debug-investigator'],
    ['run a security audit on the upload endpoint', 'ork:security-auditor'],
    ['write unit tests for the parser module', 'ork:test-generator'],
    ['review this PR for issues', 'ork:code-quality-reviewer'],
    ['create an alembic schema migration for the orders table', 'ork:database-engineer'],
    ['fix the GitHub Actions ci pipeline', 'ork:ci-cd-engineer'],
    ['do web research on competitor pricing', 'ork:web-research-analyst'],
    ['build a React component for the settings page', 'ork:frontend-ui-developer'],
    ['design the REST API endpoints for billing', 'ork:backend-system-architect'],
  ])('%s → %s', (text, expected) => {
    expect(matchSpecialistDomain(text, '')).toBe(expected);
  });

  test('matches in prompt when description is generic', () => {
    expect(
      matchSpecialistDomain('research task', 'Please write unit tests for src/auth.ts'),
    ).toBe('ork:test-generator');
  });

  test('returns null for genuinely mixed/generic tasks', () => {
    expect(matchSpecialistDomain('coordinate the milestone cleanup', 'List open issues and summarize')).toBeNull();
  });
});

describe('taskAgentAdvisor general-purpose nudge', () => {
  test('ASKS to redirect a domain-shaped general-purpose task to the specialist', () => {
    const result = taskAgentAdvisor(
      makeInput({
        subagent_type: 'general-purpose',
        description: 'Investigate the failure in CI and find the root cause',
      }),
    );

    // Enforce, not whisper: permissionDecision 'ask' surfaces the specialist
    // as an active choice. Still continue:true — never a hard deny.
    expect(result.continue).toBe(true);
    expect(decisionOf(result)).toBe('ask');
    expect(reasonOf(result)).toContain('ork:debug-investigator');
    expect(reasonOf(result)).toContain('general-purpose');
  });

  test('stays silent for general-purpose without a domain match', () => {
    const result = taskAgentAdvisor(
      makeInput({ subagent_type: 'general-purpose', description: 'summarize the meeting notes' }),
    );

    expect(result.continue).toBe(true);
    expect(decisionOf(result)).not.toBe('ask');
    expect(contextOf(result)).toBe('');
  });

  test('asks (does not hard-block) on a clear specialist domain match', () => {
    const result = taskAgentAdvisor(
      makeInput({ subagent_type: 'general-purpose', description: 'run a security audit on the upload endpoint' }),
    );
    expect(result.continue).toBe(true);          // never deny
    expect(decisionOf(result)).toBe('ask');
    expect(reasonOf(result)).toContain('ork:security-auditor');
  });

  test('other builtins (Explore) remain silent even with domain text', () => {
    const result = taskAgentAdvisor(
      makeInput({ subagent_type: 'Explore', description: 'write unit tests for x' }),
    );
    expect(contextOf(result)).toBe('');
  });
});

describe('taskAgentAdvisor deterministic-run nudge (tests/build → Bash)', () => {
  test.each([
    'knowledge/marketing tests',
    'dashboard tests',
    'misc tests',
    'Run the test suite and report results',
  ])('nudges general-purpose "%s" toward Bash', (description) => {
    const result = taskAgentAdvisor(makeInput({ subagent_type: 'general-purpose', description }));
    expect(result.continue).toBe(true);
    expect(contextOf(result)).toContain('Bash');
    expect(contextOf(result)).toContain('pytest');
  });

  test('fires for untyped (empty subagent_type) spawn — the default general-purpose path', () => {
    const result = taskAgentAdvisor(makeInput({ subagent_type: '', description: 'misc tests' }));
    expect(contextOf(result)).toContain('Bash');
  });

  test('routes a writing-tests task to ork:test-generator (ask), not the Bash nudge', () => {
    const result = taskAgentAdvisor(
      makeInput({ subagent_type: 'general-purpose', description: 'write unit tests for the parser' }),
    );
    expect(decisionOf(result)).toBe('ask');
    expect(reasonOf(result)).toContain('ork:test-generator');
    expect(reasonOf(result)).not.toContain('run it in Bash');
  });

  test('does NOT nudge a triage task (fix the failing tests stays an agent job)', () => {
    const result = taskAgentAdvisor(
      makeInput({ subagent_type: 'general-purpose', description: 'fix the failing dashboard tests' }),
    );
    expect(contextOf(result)).not.toContain('run it in Bash');
  });

  test('never blocks (advisory only)', () => {
    const result = taskAgentAdvisor(makeInput({ subagent_type: 'general-purpose', description: 'misc tests' }));
    expect(result.continue).toBe(true);
  });

  test('isDeterministicRunTask matrix (incl. sub-match edge cases)', () => {
    // fires — pure run/noun tasks
    expect(isDeterministicRunTask('dashboard tests', '')).toBe(true);
    expect(isDeterministicRunTask('Run the test suite', '')).toBe(true);
    expect(isDeterministicRunTask('run tests for the address module', '')).toBe(true); // add≠address
    expect(isDeterministicRunTask('run the fixture tests', '')).toBe(true); // fix≠fixture
    // silent — reasoning/authoring tasks
    expect(isDeterministicRunTask('fix the failing dashboard tests', '')).toBe(false);
    expect(isDeterministicRunTask('fixing the dashboard tests', '')).toBe(false);
    expect(isDeterministicRunTask('write integration tests', '')).toBe(false);
    expect(isDeterministicRunTask('explore how tests are structured', '')).toBe(false);
    expect(isDeterministicRunTask('audit the test coverage gaps', '')).toBe(false);
    expect(isDeterministicRunTask('summarize these logs', '')).toBe(false);
  });
});

describe('pre-existing advisor behaviors still intact', () => {
  test('synonym suggestion for ad-hoc names', () => {
    const result = taskAgentAdvisor(makeInput({ subagent_type: 'code-reviewer', description: 'x' }));
    expect(contextOf(result)).toContain('ork:code-quality-reviewer');
  });

  test('casing fix for builtins', () => {
    const result = taskAgentAdvisor(makeInput({ subagent_type: 'explore', description: 'x' }));
    expect(contextOf(result)).toContain('Explore');
  });

  test('unknown custom types stay silent', () => {
    const result = taskAgentAdvisor(makeInput({ subagent_type: 'my-custom-agent', description: 'x' }));
    expect(contextOf(result)).toBe('');
  });

  test('mis-cased General-Purpose gets a casing suggestion', () => {
    const result = taskAgentAdvisor(
      makeInput({ subagent_type: 'General-Purpose', description: 'x' }),
    );
    expect(contextOf(result)).toContain('`general-purpose` is the correct built-in name');
    expect(contextOf(result)).toContain('General-Purpose');
  });

  test('correct-cased general-purpose never hits the casing branch', () => {
    // The exact-case nudge branch returns first, so the casing map entry
    // for 'general-purpose' must not produce a spurious suggestion.
    const result = taskAgentAdvisor(
      makeInput({ subagent_type: 'general-purpose', description: 'summarize meeting notes' }),
    );
    expect(contextOf(result)).toBe('');
  });
});

describe('advisor edge cases', () => {
  test('first match wins when text spans two domains', () => {
    // Matches both ork:security-auditor ("security audit") and
    // ork:debug-investigator ("root cause") — the earlier registry entry wins.
    expect(
      matchSpecialistDomain('investigate the root cause of the security audit failure', ''),
    ).toBe('ork:security-auditor');
  });

  test('domain phrase beyond NUDGE_SCAN_MAX_CHARS yields no nudge', () => {
    const prompt = `${'.'.repeat(2050)} write unit tests for the parser module`;
    expect(matchSpecialistDomain('', prompt)).toBeNull();

    const result = taskAgentAdvisor(
      makeInput({ subagent_type: 'general-purpose', description: '', prompt }),
    );
    expect(contextOf(result)).toBe('');
  });
});

describe('advisor maps cross-checked against src/agents/ (map existence)', () => {
  test('AGENTS_DIR resolves to the real agents directory', () => {
    expect(existsSync(AGENTS_DIR)).toBe(true);
  });

  test.each(Object.entries(ORK_AGENT_SYNONYMS))(
    'synonym %s → %s has a matching agent definition',
    (_synonym, agent) => {
      expect(agent.startsWith('ork:')).toBe(true);
      const file = join(AGENTS_DIR, `${agent.replace('ork:', '')}.md`);
      expect(existsSync(file)).toBe(true);
    },
  );

  test.each(SPECIALIST_DOMAINS.map((d) => [d.agent] as const))(
    'specialist domain agent %s has a matching agent definition',
    (agent) => {
      expect(agent.startsWith('ork:')).toBe(true);
      const file = join(AGENTS_DIR, `${agent.replace('ork:', '')}.md`);
      expect(existsSync(file)).toBe(true);
    },
  );
});
